-- Expression index: case-insensitive email lookup
CREATE INDEX idx_users_email_lower ON users (LOWER(email));

-- Query TỰ ĐỘNG dùng expression index
SELECT * FROM users WHERE LOWER(email) = LOWER(@email);
-- hoặc (sau PostgreSQL 12 với citext extension)

-- Generated column (STORED): lưu vật lý
ALTER TABLE order_items ADD COLUMN subtotal NUMERIC(12,2)
    GENERATED ALWAYS AS (quantity * unit_price) STORED;

-- Index trên generated column
CREATE INDEX idx_items_subtotal ON order_items (subtotal);

-- Query
SELECT * FROM order_items WHERE subtotal > 1000;

-- Generated column cho full-text search (thường dùng)
ALTER TABLE products ADD COLUMN search_vector tsvector
    GENERATED ALWAYS AS (
        to_tsvector('english', coalesce(name, '') || ' ' || coalesce(description, ''))
    ) STORED;

CREATE INDEX idx_products_fts ON products USING GIN (search_vector);

-- Expression index cho JSON field
CREATE INDEX idx_orders_customer_json ON orders ((metadata->>'customer_email'));

-- Functional index cho date truncation
CREATE INDEX idx_orders_month ON orders (DATE_TRUNC('month', created_at));
-- Query:
SELECT * FROM orders WHERE DATE_TRUNC('month', created_at) = '2026-06-01';
